const DEFAULT_PRICE_USD = 0.012;

export function getModelPriceUsd(endpointOrId) {
  if (!endpointOrId) return null;
  const key = String(endpointOrId).toLowerCase();
  return Object.prototype.hasOwnProperty.call(MODEL_PRICES_USD, key) ? MODEL_PRICES_USD[key] : null;
}

// Resolve a price for a model object by trying endpoint first, then id — muapi
// aliases both in many cases (e.g. flux-dev vs flux-dev-image).
export function getModelPrice(model) {
  if (!model) return null;
  return getModelPriceUsd(model.endpoint) ?? getModelPriceUsd(model.id);
}

export function formatModelPriceUsd(price) {
  if (price == null || Number.isNaN(price)) return null;
  if (price < 0.01) return `$${price.toFixed(3)}`;
  return `$${price.toFixed(2)}`;
}

export { DEFAULT_PRICE_USD };
